// interface `device` over a channel: opcodes, a Service trait + dispatch, and a Client.
pub mod device {
	use super::*;
	use crate::codec::{Reader, Sink, SliceWriter, Transport, VecWriter};
	use alloc::vec::Vec;

	pub const OP_LIST: u16 = 1;
	pub const OP_GET: u16 = 2;

	pub trait Service {
		fn list(&mut self) -> Result<Vec<DeviceEntry>, Error>;
		fn get(&mut self, index: u32) -> Result<DeviceEntry, Error>;
	}

	pub fn dispatch<S: Service>(service: &mut S, request: &[u8], request_handle: u64, out: &mut [u8], reply_handle: &mut u64) -> Option<usize> {
		let mut reader = Reader::with_handle(request, request_handle);
		let r = &mut reader;
		let op = r.u16()?;
		let corr = r.u32()?;
		let mut writer = SliceWriter::new(out);
		match op {
			OP_LIST => {
				let result = service.list();
				let encoded: Option<()> = (|| {
					let w = &mut writer;
					w.u32(corr)?;
					match &result {
						Ok(v53) => {
							w.u8(1)?;
							if v53.len() > u16::MAX as usize {
								return None;
							}
							w.u16(v53.len() as u16)?;
							for v55 in v53.iter() {
								v55.write(w)?;
							}
						}
						Err(v54) => {
							w.u8(0)?;
							v54.write(w)?;
						}
					}
					Some(())
				})();
				if encoded.is_none() {
					// the reply outgrew the caller's buffer: replace it with a typed
					// error, so the client sees a failure instead of hanging.
					writer.reset();
					let w = &mut writer;
					w.u32(corr)?;
					w.u8(0)?;
					Error::Again.write(w)?;
				}
			}
			OP_GET => {
				let index = r.u32()?;
				let result = service.get(index);
				let encoded: Option<()> = (|| {
					let w = &mut writer;
					w.u32(corr)?;
					match &result {
						Ok(v56) => {
							w.u8(1)?;
							v56.write(w)?;
						}
						Err(v57) => {
							w.u8(0)?;
							v57.write(w)?;
						}
					}
					Some(())
				})();
				if encoded.is_none() {
					// the reply outgrew the caller's buffer: replace it with a typed
					// error, so the client sees a failure instead of hanging.
					writer.reset();
					let w = &mut writer;
					w.u32(corr)?;
					w.u8(0)?;
					Error::Again.write(w)?;
				}
			}
			_ => return None,
		}
		*reply_handle = writer.handle();
		Some(writer.pos())
	}

	pub struct Client<T: Transport> {
		transport: T,
		corr: u32,
	}

	impl<T: Transport> Client<T> {
		pub fn new(transport: T) -> Client<T> {
			Client { transport, corr: 0 }
		}
		pub fn into_transport(self) -> T {
			self.transport
		}
		fn next_corr(&mut self) -> u32 {
			let c = self.corr;
			self.corr = self.corr.wrapping_add(1);
			c
		}
		pub fn list(&mut self) -> Option<Result<Vec<DeviceEntry>, Error>> {
			let corr = self.next_corr();
			let mut writer = VecWriter::new();
			let w = &mut writer;
			w.u16(OP_LIST)?;
			w.u32(corr)?;
			let request_handle = writer.handle();
			let request = writer.into_inner();
			let (reply, reply_handle) = self.transport.call(&request, request_handle)?;
			let mut reader = Reader::with_handle(&reply, reply_handle);
			let r = &mut reader;
			if r.u32()? != corr {
				return None;
			}
			Some(if r.u8()? != 0 {
				Ok({
					let v58 = r.u16()? as usize;
					let mut v59 = Vec::new();
					for _ in 0..v58 {
						v59.push(DeviceEntry::read(r)?);
					}
					v59
				})
			} else {
				Err(Error::read(r)?)
			})
		}
		pub fn get(&mut self, index: &u32) -> Option<Result<DeviceEntry, Error>> {
			let corr = self.next_corr();
			let mut writer = VecWriter::new();
			let w = &mut writer;
			w.u16(OP_GET)?;
			w.u32(corr)?;
			w.u32(*index)?;
			let request_handle = writer.handle();
			let request = writer.into_inner();
			let (reply, reply_handle) = self.transport.call(&request, request_handle)?;
			let mut reader = Reader::with_handle(&reply, reply_handle);
			let r = &mut reader;
			if r.u32()? != corr {
				return None;
			}
			Some(if r.u8()? != 0 { Ok(DeviceEntry::read(r)?) } else { Err(Error::read(r)?) })
		}
	}
}

