// interface `config` over a channel: opcodes, a Service trait + dispatch, and a Client.
pub mod config {
	use super::*;
	use crate::codec::{Reader, Sink, SliceWriter, Transport, VecWriter};
	use alloc::vec::Vec;

	pub const OP_GET: u16 = 1;
	pub const OP_LIST: u16 = 2;
	pub const OP_SET: u16 = 3;

	pub trait Service {
		fn get(&mut self, key: String) -> Result<String, Error>;
		fn list(&mut self) -> Result<Vec<ConfigEntry>, Error>;
		fn set(&mut self, entry: ConfigEntry) -> Result<(), Error>;
	}

	pub fn dispatch<S: Service>(service: &mut S, request: &[u8], request_handle: u64, out: &mut [u8], reply_handle: &mut u64) -> Option<usize> {
		let mut reader = Reader::with_handle(request, request_handle);
		let r = &mut reader;
		let op = r.u16()?;
		let corr = r.u32()?;
		let mut writer = SliceWriter::new(out);
		match op {
			OP_GET => {
				let key = r.string_lp()?;
				let result = service.get(key);
				let encoded: Option<()> = (|| {
					let w = &mut writer;
					w.u32(corr)?;
					match &result {
						Ok(v74) => {
							w.u8(1)?;
							w.bytes_lp(v74.as_bytes())?;
						}
						Err(v75) => {
							w.u8(0)?;
							v75.write(w)?;
						}
					}
					Some(())
				})();
				if encoded.is_none() {
					// the reply outgrew the caller's buffer: replace it with a typed
					// error, so the client sees a failure instead of hanging.
					writer.reset();
					let w = &mut writer;
					w.u32(corr)?;
					w.u8(0)?;
					Error::Again.write(w)?;
				}
			}
			OP_LIST => {
				let result = service.list();
				let encoded: Option<()> = (|| {
					let w = &mut writer;
					w.u32(corr)?;
					match &result {
						Ok(v76) => {
							w.u8(1)?;
							if v76.len() > u16::MAX as usize {
								return None;
							}
							w.u16(v76.len() as u16)?;
							for v78 in v76.iter() {
								v78.write(w)?;
							}
						}
						Err(v77) => {
							w.u8(0)?;
							v77.write(w)?;
						}
					}
					Some(())
				})();
				if encoded.is_none() {
					// the reply outgrew the caller's buffer: replace it with a typed
					// error, so the client sees a failure instead of hanging.
					writer.reset();
					let w = &mut writer;
					w.u32(corr)?;
					w.u8(0)?;
					Error::Again.write(w)?;
				}
			}
			OP_SET => {
				let entry = ConfigEntry::read(r)?;
				let result = service.set(entry);
				let encoded: Option<()> = (|| {
					let w = &mut writer;
					w.u32(corr)?;
					match &result {
						Ok(v79) => {
							w.u8(1)?;
						}
						Err(v80) => {
							w.u8(0)?;
							v80.write(w)?;
						}
					}
					Some(())
				})();
				if encoded.is_none() {
					// the reply outgrew the caller's buffer: replace it with a typed
					// error, so the client sees a failure instead of hanging.
					writer.reset();
					let w = &mut writer;
					w.u32(corr)?;
					w.u8(0)?;
					Error::Again.write(w)?;
				}
			}
			_ => return None,
		}
		*reply_handle = writer.handle();
		Some(writer.pos())
	}

	pub struct Client<T: Transport> {
		transport: T,
		corr: u32,
	}

	impl<T: Transport> Client<T> {
		pub fn new(transport: T) -> Client<T> {
			Client { transport, corr: 0 }
		}
		pub fn into_transport(self) -> T {
			self.transport
		}
		fn next_corr(&mut self) -> u32 {
			let c = self.corr;
			self.corr = self.corr.wrapping_add(1);
			c
		}
		pub fn get(&mut self, key: &str) -> Option<Result<String, Error>> {
			let corr = self.next_corr();
			let mut writer = VecWriter::new();
			let w = &mut writer;
			w.u16(OP_GET)?;
			w.u32(corr)?;
			w.bytes_lp(key.as_bytes())?;
			let request_handle = writer.handle();
			let request = writer.into_inner();
			let (reply, reply_handle) = self.transport.call(&request, request_handle)?;
			let mut reader = Reader::with_handle(&reply, reply_handle);
			let r = &mut reader;
			if r.u32()? != corr {
				return None;
			}
			Some(if r.u8()? != 0 { Ok(r.string_lp()?) } else { Err(Error::read(r)?) })
		}
		pub fn list(&mut self) -> Option<Result<Vec<ConfigEntry>, Error>> {
			let corr = self.next_corr();
			let mut writer = VecWriter::new();
			let w = &mut writer;
			w.u16(OP_LIST)?;
			w.u32(corr)?;
			let request_handle = writer.handle();
			let request = writer.into_inner();
			let (reply, reply_handle) = self.transport.call(&request, request_handle)?;
			let mut reader = Reader::with_handle(&reply, reply_handle);
			let r = &mut reader;
			if r.u32()? != corr {
				return None;
			}
			Some(if r.u8()? != 0 {
				Ok({
					let v81 = r.u16()? as usize;
					let mut v82 = Vec::new();
					for _ in 0..v81 {
						v82.push(ConfigEntry::read(r)?);
					}
					v82
				})
			} else {
				Err(Error::read(r)?)
			})
		}
		pub fn set(&mut self, entry: &ConfigEntry) -> Option<Result<(), Error>> {
			let corr = self.next_corr();
			let mut writer = VecWriter::new();
			let w = &mut writer;
			w.u16(OP_SET)?;
			w.u32(corr)?;
			entry.write(w)?;
			let request_handle = writer.handle();
			let request = writer.into_inner();
			let (reply, reply_handle) = self.transport.call(&request, request_handle)?;
			let mut reader = Reader::with_handle(&reply, reply_handle);
			let r = &mut reader;
			if r.u32()? != corr {
				return None;
			}
			Some(if r.u8()? != 0 { Ok(()) } else { Err(Error::read(r)?) })
		}
	}
}

